class StatsData(AvitoObject):
    """Данные статистики за период

    See: https://developers.avito.ru/api-catalog/ads/documentation

    Attributes:
        clicks: Количество кликов
        cpc: Средняя стоимость CPC
        cpm: Средняя стоимость CPM
        ctr: CTR (Click-Through Rate)
        q25: Доля просмотров видео на 25%
        q50: Доля просмотров видео на 50%
        q75: Доля просмотров видео на 75%
        spend: Потрачено денег в рублях
        spend_bonus: Потрачено бонусов в рублях
        spend_bonus_kopeks: Потрачено бонусов в копейках
        spend_kopeks: Потрачено денег в копейках
        timestamp: Временная метка (гранулярность по дням). Заполняется в data[] и отсутствует в totalData.
        video_views100: Количество просмотров видео на 100%
        video_views25: Количество просмотров видео на 25%
        video_views50: Количество просмотров видео на 50%
        video_views75: Количество просмотров видео на 75%
        views: Количество показов
        vtr: Доля просмотров видео на 100%
    """

    clicks: int
    cpc: float
    cpm: float
    ctr: float
    q25: float | None = None
    q50: float | None = None
    q75: float | None = None
    spend: int
    spend_bonus: int = Field(..., alias="spendBonus")
    spend_bonus_kopeks: int | None = Field(None, alias="spendBonusKopeks")
    spend_kopeks: int | None = Field(None, alias="spendKopeks")
    timestamp: TZDatetime | None = None
    video_views100: int | None = Field(None, alias="videoViews100")
    video_views25: int | None = Field(None, alias="videoViews25")
    video_views50: int | None = Field(None, alias="videoViews50")
    video_views75: int | None = Field(None, alias="videoViews75")
    views: int
    vtr: float | None = None


