class V1CreateContractIn(AvitoObject):
    """Payload запроса на создание договора. Базово обязательны `description`, `advertiserId`, `type`. Для `type = service` дополнительно передаются `subject`, `isReportingRequired`, `date`, `number`; `cid` не передаётся. Для `type = intermediary` дополнительно передаются `subject`, `object`, `isReportingRequired`, `isFundsAllocationToPrincipal`, `date`, `number`; `cid` не передаётся. Для `type = external` передаётся `cid`; `parentId` не передаётся. Дополнительное соглашение создаётся через `parentId` к родительскому договору, без отдельного `type = additional`. Если `parentId` задан, `intermediary` не передаётся; если `parentId` не задан, `intermediary` обязателен.

    See: https://developers.avito.ru/api-catalog/ads/documentation

    Attributes:
        advertiser_id: Id рекламодателя. Указываем только рекламодателей которые не являются аккаунтом. Если рекламодатель и аккаунт одно и тоже ЮЛ, договор создавать не надо
        cid: CID внешнего договора, заполняется только для type = external.
        date_: Дата в формате YYYY-MM-DD. Можно не передавать только для type = external.
        is_funds_allocation_to_principal: Денежные средства на размещение рекламы идут в сторону принципала
        is_reporting_required: На исполнителе лежит обязанность отчитываться по креативам
        number: Номер договора. Можно не передавать только для type = external.
        parent_id: ID родительского договора для доп. соглашения
    """

    advertiser_id: int = Field(..., alias="advertiserId")
    cid: str | None = None
    date_: date | None = Field(None, alias="date")
    description: ContractCounterpartyType
    intermediary: CreteIntermediaryIn | None = None
    is_funds_allocation_to_principal: bool | None = Field(
        None, alias="isFundsAllocationToPrincipal"
    )
    is_reporting_required: bool | None = Field(None, alias="isReportingRequired")
    number: str | None = None
    object: ContractAction | None = None
    parent_id: int | None = Field(None, alias="parentId")
    subject: ContractSubject | None = None
    type_: ContractType = Field(..., alias="type")


